{
  "editorMode": "normal",
  "enabledPlugins": {
    "beads@beads-marketplace": false
  },
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash(gh pr create*)",
        "hooks": [
          {
            "type": "command",
            "command": "export PATH=\"$HOME/go/bin:$HOME/.local/bin:$PATH\" && gt tap guard pr-workflow"
          }
        ]
      },
      {
        "matcher": "Bash(git checkout -b*)",
        "hooks": [
          {
            "type": "command",
